// ── Grade conversion ──
const gradeValue: Record<string, number> = { "A*": 6, "A": 5, "B": 4, "C": 3, "D": 2, "E": 1 };

function parseRequirement(req: string): number[] {
  const grades: number[] = [];
  let i = 0;
  while (i < req.length) {
    if (req[i] === "A" && req[i + 1] === "*") {
      grades.push(6);
      i += 2;
    } else {
      grades.push(gradeValue[req[i]] || 0);
      i++;
    }
  }
  return grades.sort((a, b) => b - a);
}

